css:
@page {
    size: A4;
    margin: 1cm;
}

body{
    font-family: "Segoe UI", Arial, sans-serif;
    font-size:13px;
    color:#333;
}

/* Header */

.header{
    background:#2f4f87;
    color:white;
    text-align:center;
    padding:20px;
    border-radius:8px;
    margin-bottom:20px;
}

.header h1{
    margin:0;
    font-size:26px;
}

.job-id{
    display:inline-block;
    margin-top:10px;
    background:#4d6faa;
    padding:6px 14px;
    border-radius:20px;
    font-size:14px;
}

/* Section Titles */

.section-title{
    font-size:18px;
    font-weight:bold;
    color:#2f4f87;
    margin-top:20px;
    border-bottom:2px solid #2f4f87;
    padding-bottom:5px;
}

/* Two Column Layout */

.two-col{
    display:flex;
    justify-content:space-between;
    margin-top:10px;
}

.col{
    width:48%;
}

p{
    margin:6px 0;
}

/* Problem Box */

.problem-box{
    background:#eef1f6;
    padding:8px;
    border-left:4px solid #2f4f87;
    margin-top:10px;
}

/* Table */

.parts-table{
    width:100%;
    border-collapse:collapse;
    margin-top:10px;
}

.parts-table th{
    background:#355a9b;
    color:white;
    padding:8px;
    text-align:center;
}

.parts-table td{
    border:1px solid #ccc;
    padding:8px;
    text-align:center;
}

/* Total Box */

.total-box{
    margin-top:15px;
    background:#f4f6fa;
    border-left:4px solid #2f4f87;
    padding:12px;
}

.final-amount{
    font-size:20px;
    font-weight:bold;
    color:#1f3e73;
    margin-top:8px;
}

/* Footer */

.footer{
    text-align:center;
    font-size:11px;
    color:#777;
    margin-top:20px;
}

/* Page Break */

.page-break{
    page-break-before:always;
}

@media print{
.no-print{
display:none;
}
}
